mapper.sql:
WHERE permission_detail.id is not NULL
AND permission_detail.deleted = #{deleted}
AND permission_detail.created_at >= CONCAT(#{sdate}, ' 00:00:00')
AND CONCAT(#{fdate}, ' 23:59:59') >= permission_detail.created_at
AND permission_detail.permission_id = #{permissionId}
AND permission_detail.target = #{target}
AND permission_detail.func = #{func}
